import React, { useCallback, useEffect, useMemo, useState } from 'react';
import { useSearchParams } from 'react-router-dom';
import {
  Input,
  Select,
  dispatchAppToast,
  LIN_ERP_LIST_FILTER_LAYOUT,
  LinErpListFilterBar,
  LinPageLayout,
  useCatalogTableBusy,
  useErpListSelection,
} from '@linm-soft-org/linm-web-common-components';
import { useAppDispatch } from '../../../store/hooks';
import { useStockBalancePermissions } from '../../../hooks/useStockBalancePermissions';
import { useVoucherInitData } from '../../../hooks/useVoucherInitData';
import { wmsService } from '../../../services/kho/wmsService';
import type { StockLedgerLineDto } from '../../../services/kho/models';
import { khoReportPageLabels } from '../../../constants/khoReportPageLabels';
import { formatNumber, formatMoneyVnd, formatDate } from '../../../utils/formatters';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import { WmsSourceDocumentSlideout } from '../../../components/report/WmsSourceDocumentSlideout';
import { buildKhoReportListToolbar } from '../../../features/kho/reportListToolbar';
import erp from '../../../styles/erpPage.module.css';

const labels = khoReportPageLabels.theKho;
const TEST_ID = 'erp-kho-the-kho';
const PAGE_ID = 'kho-the-kho';

const TheKhoPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const [searchParams] = useSearchParams();
  useStockBalancePermissions();
  const [materialCode, setMaterialCode] = useState('');
  const [warehouseId, setWarehouseId] = useState('');
  const [asOfDate, setAsOfDate] = useState(() => new Date().toISOString().slice(0, 10));
  const [items, setItems] = useState<StockLedgerLineDto[]>([]);
  const [loading, setLoading] = useState(false);
  const [materialError, setMaterialError] = useState<string | undefined>();
  const [slideoutRow, setSlideoutRow] = useState<StockLedgerLineDto | null>(null);
  const { showTableLoading } = useCatalogTableBusy(loading);

  const { warehouseOptions } = useVoucherInitData('stock-ledger-filter');
  const whOpts = [{ value: '', label: labels.warehouseAll }, ...warehouseOptions];

  const gridRows = useMemo(
    () => items.map((r, i) => ({ ...r, id: r.id || String(i) })),
    [items],
  );

  const selection = useErpListSelection({
    rows: gridRows,
    totalCount: gridRows.length,
    page: 1,
    pageSize: Math.max(gridRows.length, 1),
    getRowId: r => r.id,
  });

  useEffect(() => {
    const code = searchParams.get('materialCode')?.trim();
    if (code) setMaterialCode(code);
  }, [searchParams]);

  const handleLoad = useCallback(() => {
    const code = materialCode.trim();
    if (!code) {
      setMaterialError(labels.materialRequired);
      dispatchAppToast(dispatch, {
        message: labels.filterValidationSummary,
        type: 'warning',
      });
      return;
    }
    setMaterialError(undefined);
    setLoading(true);
    wmsService.getStockLedger({
      materialCode: code,
      warehouseId: warehouseId || undefined,
      toDate: asOfDate ? `${asOfDate}T23:59:59.999Z` : undefined,
    })
      .then(setItems)
      .catch(err => {
        dispatchAppToast(dispatch, {
          message: getApiErrorMessage(err, labels.loadError),
          type: 'error',
        });
      })
      .finally(() => setLoading(false));
  }, [materialCode, warehouseId, asOfDate, dispatch]);

  const totalIn = items.reduce((sum, r) => sum + (r.inQty ?? 0), 0);
  const totalOut = items.reduce((sum, r) => sum + (r.outQty ?? 0), 0);
  const hasData = items.length > 0;

  const openDrill = useCallback((row: StockLedgerLineDto) => {
    if (row.canOpenSourceDocument && row.sourceDocumentId) {
      setSlideoutRow(row);
    }
  }, []);

  const listFilters = useMemo(
    () => (
      <LinErpListFilterBar
        testIdPrefix={TEST_ID}
        fromDate={asOfDate}
        toDate={undefined}
        dateLabel="Đến ngày"
        onDateChange={from => setAsOfDate(from ?? '')}
        onSearch={handleLoad}
        searchAriaLabel={labels.view}
        loading={showTableLoading}
        leading={(
          <>
            <div data-testid={`${TEST_ID}-field-material`}>
              <Input
                label="Mã vật tư"
                required
                value={materialCode}
                onChange={e => {
                  setMaterialCode(e.target.value);
                  if (materialError) setMaterialError(undefined);
                }}
                error={materialError}
                placeholder={labels.materialPlaceholder}
                fullWidth
                data-testid={`${TEST_ID}-filter-material`}
              />
            </div>
            <div data-testid={`${TEST_ID}-field-warehouse`}>
              <Select
                label="Kho"
                value={warehouseId}
                onChange={e => setWarehouseId(e.target.value)}
                options={whOpts}
                fullWidth
                data-testid={`${TEST_ID}-filter-warehouse`}
              />
            </div>
          </>
        )}
      />
    ),
    [materialCode, materialError, warehouseId, asOfDate, whOpts, handleLoad, showTableLoading],
  );

  const toolbarProps = useMemo(
    () => ({
      testIdPrefix: TEST_ID,
      profile: 'report' as const,
      actions: buildKhoReportListToolbar({
        testIdPrefix: TEST_ID,
        onRefresh: handleLoad,
        canPrint: hasData,
        onPrint: () => window.print(),
      }),
    }),
    [handleLoad, hasData],
  );

  const listBody = showTableLoading ? null : (
    <div className={erp.tableWrapper} data-testid={`${TEST_ID}-grid`}>
      <table className={erp.table}>
        <thead>
          <tr>
            <th>Ngày</th>
            <th>Loại</th>
            <th>Số CT</th>
            <th className={erp.colRight}>Nhập</th>
            <th className={erp.colRight}>Xuất</th>
            <th className={erp.colRight}>ĐG</th>
          </tr>
        </thead>
        <tbody>
          {items.length === 0 ? (
            <tr><td colSpan={6}><div className={erp.empty}>{labels.empty}</div></td></tr>
          ) : items.map((row, i) => (
            <tr
              key={row.id}
              data-testid={`${TEST_ID}-row-${i}`}
              className={selection.activeRow?.id === row.id ? erp.rowSelected : undefined}
              onClick={() => selection.selectActiveRow({ ...row, id: row.id })}
              onDoubleClick={() => openDrill(row)}
              style={{ cursor: row.canOpenSourceDocument ? 'pointer' : 'default' }}
            >
              <td>{formatDate(row.movementDate)}</td>
              <td>{row.movementType}</td>
              <td>{row.voucherCode ?? '—'}</td>
              <td className={erp.colRight}>{formatNumber(row.inQty)}</td>
              <td className={erp.colRight}>{formatNumber(row.outQty)}</td>
              <td className={erp.colRight}>{formatMoneyVnd(row.unitPrice)}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );

  return (
    <div
      className={erp.voucherListRoot}
      data-catalog-list-page
      data-report-list-page
      data-testid={`${TEST_ID}-list`}
    >
      <LinPageLayout
        kind="report"
        testIdPrefix={TEST_ID}
        pageId={PAGE_ID}
        pageClassName={`${erp.catalogListPage} ${erp.voucherListPage}`}
        header={{
          title: labels.title,
          titleIconClass: 'fas fa-id-card',
          pageId: PAGE_ID,
        }}
        toolbarProps={toolbarProps}
        listTitle={labels.listTitle}
        filters={listFilters}
        listLayoutVariant="erp-filter-bar"
        listHeaderClassName={LIN_ERP_LIST_FILTER_LAYOUT.header}
        listFiltersClassName={LIN_ERP_LIST_FILTER_LAYOUT.filtersHost}
        showTableLoading={showTableLoading}
        skeletonRows={8}
        footer={hasData ? (
          <div className={erp.paginationRow} data-testid={`${TEST_ID}-summary`}>
            <span className={erp.totalCount}>
              {labels.summaryTotals(formatNumber(totalIn - totalOut), formatMoneyVnd(0))}
            </span>
          </div>
        ) : undefined}
        modals={(
          <WmsSourceDocumentSlideout
            isOpen={slideoutRow != null}
            onClose={() => setSlideoutRow(null)}
            documentType={slideoutRow?.sourceDocumentType ?? null}
            documentId={slideoutRow?.sourceDocumentId ?? null}
            sourceDocumentViewUrl={slideoutRow?.sourceDocumentViewUrl}
            voucherCode={slideoutRow?.voucherCode ?? undefined}
            title={labels.slideoutTitle}
            returnTitle={labels.title}
            closeLabel={labels.slideoutClose}
            openFullLabel={labels.slideoutOpenFull}
            testIdPrefix={TEST_ID}
          />
        )}
      >
        {listBody}
      </LinPageLayout>
    </div>
  );
};

export default TheKhoPage;
